def isEmpty(stack):
    return len(stack) == 0

def push(stack, element):
    stack.append(element)
    print(element, 'pushed to stack')

def pop(stack):
    if isEmpty(stack):
        print('Stack Underflow! Stack is empty.')
        return None
    return stack.pop()

def peek(stack):
    if isEmpty(stack):
        print('Stack is empty.')
        return None
    return stack[-1]

def display(stack):
    if isEmpty(stack):
        print('Stack is empty.')
    else:
        print('Stack (top to bottom):')
        for i in range(len(stack) - 1, -1, -1):
            print(stack[i])

# Main program
stack = []
push(stack, 10)
push(stack, 20)
push(stack, 30)
display(stack)
print('Top element:', peek(stack))
print('Popped:', pop(stack))
display(stack)

def is_palindrome(string):
    stack = []
    # Push all characters onto the stack
    for char in string:
        stack.append(char)
    # Pop characters and build reversed string
    reversed_str = ''
    while len(stack) > 0:
        reversed_str += stack.pop()
    # Compare
    if string == reversed_str:
        return True
    else:
        return False

# Test
word = input('Enter a string: ')
if is_palindrome(word):
    print(word, 'is a palindrome')
else:
    print(word, 'is not a palindrome')

stack = []

def push_student():
    rollno = int(input('Enter roll number: '))
    name = input('Enter name: ')
    student = (rollno, name)
    stack.append(student)
    print('Student record pushed successfully.')

def pop_student():
    if len(stack) == 0:
        print('Stack Underflow! No records to remove.')
    else:
        student = stack.pop()
        print('Removed student — Roll No:', student[0], 'Name:', student[1])

def display_stack():
    if len(stack) == 0:
        print('Stack is empty.')
    else:
        print('Student Records (top to bottom):')
        for i in range(len(stack) - 1, -1, -1):
            print('Roll No:', stack[i][0], 'Name:', stack[i][1])

# Menu-driven program
while True:
    print('\n--- Stack Menu ---')
    print('1. Push student record')
    print('2. Pop student record')
    print('3. Display stack')
    print('4. Exit')
    choice = int(input('Enter your choice: '))
    if choice == 1:
        push_student()
    elif choice == 2:
        pop_student()
    elif choice == 3:
        display_stack()
    elif choice == 4:
        print('Exiting program.')
        break
    else:
        print('Invalid choice!')
